AuthService <pre><code>class AuthService implements DoxService {
    @override
    void setup() {
        Auth.initialize(AuthConfig(
        /// default auth guard
        defaultGuard: 'web',

        /// list of auth guards
        guards: &lt;String, AuthGuard&gt;{
            'web': AuthGuard(
            driver: JwtAuthDriver(secret: SecretKey(Env.get('APP_KEY'))),
            provider: AuthProvider(
                model: () =&gt; User(),
            ),
            ),
        },
        ));
    }
}
</code></pre>

