CreateWith migration <pre><code>dox create:model Blog
</code></pre> <pre><code>dox create:model Blog -m
</code></pre> <p>Info</p> <p>This will create a blog model inside <code>lib/models</code> folder.</p> <p>Warning</p> <p>Please run <code>dart run build_runner build</code> after new model is created. Alternatively can also run build_runner watch <code>dart run build_runner watch</code> to update changes to generator file</p> Sample Model <pre><code>import 'package:illuminate_database/query_builder.dart';
part 'blog.model.g.dart';

@DoxModel()
class Blog extends BlogGenerator {
  @Column()
  String? title;

  @Column(name: 'title', beforeSave: makeSlug)
  String? slug;

  @Column()
  String? status;

  @Column(name: 'body')
  String? description;

  @Column(name: 'created_at')
  DateTime? createdAt;

  @Column(name: 'updated_at')
  DateTime? updatedAt;

  static makeSlug(Map&lt;String, dynamic&gt; map) {
    return Slugify().slugify(map['title']);
  }
}
</code></pre>

