blog.request.dartblog.controller.dart <pre><code>import 'package:illuminate_foundation/foundation.dart';

class BlogRequest extends FormRequest {
    String? title;
    String? description;

    @override
    void setUp() {
        title = input('title');
        description = input('desc');
    }

    @override
    Map&lt;String, String&gt; rules() {
        return {
            'title': 'required',
        };
    }

    @override
